diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
index fdadf729fbd5..c5ddf17af0c4 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -8071,6 +8071,20 @@ Instruction *InstCombinerImpl::visitFCmpInst(FCmpInst &I) {
   if (Instruction *R = foldFabsWithFcmpZero(I, *this))
     return R;

+  // fcmp oeq/une (select Cond, X, -X), 0.0 --> fcmp oeq/une X, 0.0
+  // fcmp oeq/une (select Cond, -X, X), 0.0 --> fcmp oeq/une X, 0.0
+  if ((Pred == FCmpInst::FCMP_OEQ || Pred == FCmpInst::FCMP_UNE ||
+       Pred == FCmpInst::FCMP_UEQ || Pred == FCmpInst::FCMP_ONE ||
+       Pred == FCmpInst::FCMP_ORD || Pred == FCmpInst::FCMP_UNO) &&
+      match(Op1, m_AnyZeroFP())) {
+    Value *T, *F;
+    if (match(Op0, m_Select(m_Value(), m_Value(T), m_Value(F)))) {
+      if (match(T, m_FNeg(m_Specific(F))) || match(F, m_FNeg(m_Specific(T)))) {
+        return new FCmpInst(Pred, T, Op1, "", &I);
+      }
+    }
+  }
+
   if (match(Op0, m_FNeg(m_Value(X)))) {
     // fcmp pred (fneg X), C --> fcmp swap(pred) X, -C
     Constant *C;
