   return nullptr;
 }

+Instruction *InstCombinerImpl::foldSelectInstWithFCmp(SelectInst &SI, FCmpInst *FCI) {
+  Value *TrueVal = SI.getTrueValue();
+  Value *FalseVal = SI.getFalseValue();
+  FCmpInst::Predicate Pred = FCI->getPredicate();
+  Value *CmpLHS = FCI->getOperand(0);
+  Value *CmpRHS = FCI->getOperand(1);
+
+  if (CmpRHS != CmpLHS && isa<Constant>(CmpRHS) && !isa<Constant>(CmpLHS)) {
+    if (CmpLHS == TrueVal && Pred == FCmpInst::FCMP_OEQ) {
+      // Transform (X == C) ? X : Y -> (X == C) ? C : Y
+      replaceOperand(SI, 1, CmpRHS);
+      return &SI;
+    } else if (CmpLHS == FalseVal && Pred == FCmpInst::FCMP_UNE) {
+      // Transform (X != C) ? Y : X -> (X != C) ? Y : C
+      replaceOperand(SI, 2, CmpRHS);
+      return &SI;
+    }
+  }
+  return nullptr;
+}
+
